  .poll(() => fireflyImageGenerationMock.getGenerationCallCount(), {
    message: 'expected the generation mock to be called at least once',
  })
  .toBeGreaterThanOrEqual(1);

const payload = fireflyImageGenerationMock.getLastPayload();
expect(payload?.prompt).toBe(PROMPT);
```

